  ('dietitian-moex-08024', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '政府勞動基準法中有關「技術生」的規定，下列敘述何者正確？', '["雇主得向技術生收取有關訓練費用", "技術生人數，不得超過勞工人數六分之一", "技術生災害補償所採薪資計算之標準，得低於基本工資", "雇主不得招收未滿15歲之人為技術生，但國民中學畢業者，不在此限"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08025', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列有關團膳業損益平衡分析（Break-even Analysis）的敘述，何者錯誤？', '["損益平衡點（Break-even Point）即不賺不賠的分界點", "邊際利益率（Contribution Margin Rate）和變動成本率（Variable Cost Rate）總和恰為2", "利潤（Profit）即總營業收入扣除變動與固定成本所剩餘的部分", "邊際利益（Contribution Margin）又稱粗利潤"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08026', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '預估食物成本百分比時，下列敘述何者正確？', '["食物成本百分比＝預計收入（ ）－其他費用 （管理費＋營業費）－利潤百分比 100% %", "食物成本百分比＝食物總售價×100%÷食物成本價", "變動成本＝變動成本率÷總營業額", "變動成本率＝1＋貢獻率"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08027', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列有關團膳業市場菜品售價的敘述，何者錯誤？', '["食物成本包含生鮮原料、調味料與盤飾等費用", "營運管理費包含租金、折舊費、財產稅等", "透過標準食譜的建構，有助於提升菜品定價精準度", "一般而言，單點菜單較有助於食物成本計算"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08028', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列何者可幫助管理者推估或判斷菜單售價、銷售量或成本的變動對利潤的影響？', '["損益平衡分析", "預算製定", "食物成本分析", "資產負債表分析"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
